+fn inferParamType(self: *ZigCodeGenerator, param_name: []const u8, body: []const ast.Node) []const u8 {
+    for (body) |node| {
+        const param_type = inferParamTypeInNode(self, param_name, node);
+        if (param_type) |t| return t;
+    }
+    return "i64"; // Default to i64
+}
